body:
Hi @aymeric-giraudet,

Thats indeed the case, we have very dynamic routes based on our CMS system.

So a route can be category page but also a product page.

We have a [...all].js then in getStaticProps we check what kind of page we need to load and the render method is like this:

```
{(pageType === 'product') ? (
    <ProductPage
        {...props}
    />
) : (
    <ConditionalWrapper
        condition={(!isEmpty(index))}
        wrapper={(children) => (
            <InstantSearchSSRProvider
                {...serverState}
                key={getProviderKey({ path: router.asPath })}
            >
                <InstantSearch
                    {...index}
                    serverStateProps={serverStateProps}
                >
                    {children}
                </InstantSearch>
            </InstantSearchSSRProvider>
        )}
    >
        <BlocksPage
            {...props}
        />
    </ConditionalWrapper>
)}
```

So we are navigating to a product and the instant search index is gone. But we are still on the same route for nextjs.

Hope this clears the issue for you.

Great! Yeah i am aware of the separated pages but this client wants extreme flexibility. I simple do not know what the url will be or what kind of page will be on it.

Here is my router implemention:

```
// @todo
// To use algolia-next.js this bug should be resolved first
// https://github.com/algolia/instantsearch/issues/5586

let {
	indexParams,
	filterDivider,
	segmentOrder,
} = CategoryConfig;

export const router = ({
	filters,
	indexName,
	serverStateProps = {},
}) => {
	let { path } = serverStateProps;

	indexName = getIndexName({ indexName });

	return {
		router: createInstantSearchRouterNext({
			routerOptions: {
				createURL: ({
					routeState,
					location,
				}) => {
					let url = getCleanPath({ path: location.pathname });
					let indexParamsValues = Object.values(indexParams);
					let filterUrl = filterDivider;

					for (let indexParamsKey of segmentOrder) {
						if (routeState[indexParams[indexParamsKey]]) {
							url += `${indexParams[indexParamsKey]}-${routeState[indexParams[indexParamsKey]]}/`;
						}
					}

					Object.keys(routeState).forEach((key) => {
						let value = routeState[key];

						if (value) {
							if (Array.isArray(value)) {
								value = map(value, (o) => encodeURIComponent(o));
							} else {
								value = encodeURIComponent(value);
							}

							if (!indexParamsValues.includes(key)) {
								filterUrl += `/${encodeURIComponent(key)}:${value.join(',')}`;
							}
						}
					});

					if (filterUrl !== filterDivider) {
						url += `${filterUrl}/`;
					}

					return url;
				},
				parseURL: ({
					location,
				}) => {
					let url = new URL(location);
					let routeState = {};

					for (let indexParamValue of Object.values(indexParams)) {
						let regex = new RegExp(`/${indexParamValue}-[^/]*`, 'g');
						let findIndexParam = regex.exec(url.pathname);

						if (Array.isArray(findIndexParam) && findIndexParam.length > 0) {
							routeState[indexParamValue] = findIndexParam[0].replace(`/${indexParamValue}-`, '');
						}
					}

					if (url.pathname.indexOf(filterDivider) !== -1) {
						let segments = url.pathname.split('/');
						let filterIndex = segments.indexOf('filter');
						let filters = [];

						segments.forEach((segment, index) => {
							if (segment && segment !== 'filter') {
								if (filterIndex !== -1 && index > filterIndex) {
									filters.push(segment);
								}
							}
						});

						if (!isEmpty(filters)) {
							filters.forEach((filter) => {
								if (filter) {
									let [key, value] = filter.split(':');

									if (value) {
										value = value.split(',');

										if (Array.isArray(value)) {
											value = map(value, (o) => decodeURIComponent(o));
										}

										routeState[key] = value;
									}
								}
							});
						}
					}

					return routeState;
				},
			},
			serverUrl: (path) ? `${process.env.NEXT_PUBLIC_BASE_URL}${path}` : process.env.NEXT_PUBLIC_BASE_URL,
			singletonRouter,
		}),
		stateMapping: {
			stateToRoute(uiState) {
				let routeState = {};
				let indexUiState = uiState[indexName];

				if (indexUiState) {
					routeState = {
						pagina: indexUiState.page,
						query: indexUiState.query,
						sorteren: getSortByValue({
							indexName,
							value: indexUiState.sortBy,
						}),
					};

					if (Array.isArray(filters)) {
						filters.forEach(({
							attribute,
							label,
						}) => {
							let urlKey = slugify(label);

							if (indexUiState?.refinementList?.[attribute]) {
								routeState[urlKey] = indexUiState.refinementList[attribute];
							}
						});
					}

					routeState = omitBy(routeState, isNil);
				}

				return routeState;
			},
			routeToState(routeState) {
				let uiState = routeState;

				if (indexName) {
					let indexUiState = {
						page: (routeState.pagina) ? parseInt(routeState.pagina) : undefined,
						query: routeState.query,
						sortBy: getSortByValue({
							indexName,
							routeState: true,
							value: routeState.sorteren,
						}),
						refinementList: {},
					};

					if (Array.isArray(filters)) {
						filters.forEach(({
							attribute,
							label,
						}) => {
							let urlKey = slugify(label);

							if (routeState?.[urlKey]) {
								indexUiState.refinementList[attribute] = routeState[urlKey];
							}
						});
					}

					indexUiState = omitBy(indexUiState, isNil);
					indexUiState.refinementList = omitBy(indexUiState.refinementList, isNil);

					if (isEmpty(indexUiState.refinementList)) {
						delete indexUiState.refinementList;
					}

					uiState = {
						[indexName]: indexUiState,
					};
				}

				return uiState;
			},
		},
	};
};
```

CategoryConfig:

```
export default {
	filterDivider: 'filter',
	indexParams: {
		page: 'pagina',
		query: 'query',
		sortBy: 'sorteren',
	},
	segmentOrder: ['sortBy', 'query', 'page'],
};
```

Please let me know if I can help.
